import React, {useState, useEffect} from 'react';
import { Table, Thead, Tbody, Tr, Th, Td, ChakraProvider, Box } from '@chakra-ui/react';
import Axios from 'axios';

const Application = () => {

  const [data, setData] = useState([])

  useEffect(() => {
    Axios.get('http://localhost:3001/api/utilisateur').then(res => setData(res.data))
  }, [])

  const Obtenir_element_nom = () => {
    return data.map(donnee => {
      return (
        <Tr>
          <Td>{donnee.id}</Td>
          <Td>{donnee.etablissement_type}</Td>
          <Td>{donnee.etablissement}</Td> 
          <Td>{donnee.location}</Td> 
          <Td>{donnee.address}</Td> 
          <Td>{donnee.mail}</Td> 
        </Tr>
      )
    })
  }

  return (
   <div>
    <ChakraProvider>
     <Box p={2}>
      <Table>
        <Thead>
          <Tr>
            <Th>id</Th>
            <Th>etablissement_type</Th>
            <Th>etablissement</Th>
            <Th>location</Th>
            <Th>address</Th>
           <Th>mail</Th>
          </Tr>
        </Thead>
        <Tbody>{Obtenir_element_nom()}</Tbody>
      </Table>
     </Box>  
    </ChakraProvider>
    </div>
  )
}
export default Application;
